  ('elementary-0489de64-moex-00391', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '若客運業者維修的單位成本相對於駕駛單位成本增加時，業者的駕駛成本支出反而提高，此反應出 下列那一個經濟特性？', '["駕駛對維修的投入要素替代彈性為正數", "駕駛對維修的投入要素替代彈性為負數", "駕駛對維修的投入要素邊際技術替代率大於1", "駕駛對維修的投入要素邊際技術替代率小於1"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00392', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '聯合國的可持續發展目標（SDGs）旨在促進全球範圍內的可持續發展。在下列目標中，那一項與運 輸系統之可持續發展相關？', '["結束貧困，確保所有人都能享受繁榮和滿足基本的生活需求", "確保城市與人類居住具包容、安全、韌性及永續性", "確保可持續消費和生產模式，鼓勵企業實施更環保的生產方法", "保護、恢復和促進可持續利用陸地生態系統，實現陸地生物多樣性的保護"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00393', 'elementary-0489de64', 'elementary-0489de64-moex-112-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '大眾捷運系統依使用路權型態分為「完全獨立專用路權」及「非完全獨立專用路權」，如果採非完全獨 立專用路權者，其共用車道路線長度，以不超過全部路線多少為限？', '["二分之一", "三分之一", "四分之一", "五分之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "e35adbcd1d79", "answer_pdf_sha1": "398158e7c48d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "511", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00394', 'elementary-0489de64', 'elementary-0489de64-moex-112-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '交通部鐵道局為中央行政機關之幾級機關？', '["一級機關", "二級機關", "三級機關", "四級機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "e35adbcd1d79", "answer_pdf_sha1": "398158e7c48d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "511", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00395', 'elementary-0489de64', 'elementary-0489de64-moex-112-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '依行政程序法規定，有關行政管轄權之敘述，下列何者錯誤？', '["行政機關之管轄權，依其組織法規或其他行政法規定之", "同一事件，數行政機關均有管轄權者，由受理在先之機關管轄", "關於企業之經營或其他繼續性事業之事件，依企業申請處所為管轄機關", "數行政機關於管轄權有爭議時，由其共同上級機關決定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "e35adbcd1d79", "answer_pdf_sha1": "398158e7c48d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "511", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00396', 'elementary-0489de64', 'elementary-0489de64-moex-112-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '汽車運輸業營運成本重估及運價調整，除遇有特殊情形外，幾年檢討一次？', '["每1年", "每2年", "每3年", "每4年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "e35adbcd1d79", "answer_pdf_sha1": "398158e7c48d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "511", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
