  ('elementary-0489de64-moex-00398', 'elementary-0489de64', 'elementary-0489de64-moex-112-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '經營計程車客運業應遵守下列規定，何者正確？', '["車輛應裝設計程車計費表，並按規定收費，且必須安裝營業區域以外費率之計程車計費表", "車輛新領牌照或汰舊換新時，車身顏色應為純黃顏色，多元化計程車亦應該使用前開車身顏色", "僱用或解僱駕駛人，應向核發計程車駕駛人執業登記證之警察機關辦理申報", "車輛應不需要由具有效職業駕駛執照及計程車駕駛人執業登記證之駕駛人駕駛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "e35adbcd1d79", "answer_pdf_sha1": "398158e7c48d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "511", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00399', 'elementary-0489de64', 'elementary-0489de64-moex-112-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '營業小客車之車牌顏色為何？', '["紅底白字", "白底黑字", "綠底白字", "白底紅字"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "e35adbcd1d79", "answer_pdf_sha1": "398158e7c48d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "511", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00400', 'elementary-0489de64', 'elementary-0489de64-moex-112-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '有關計程車牌照之發放，下列敘述何者正確？', '["應依照縣、市人口及經濟成長比例發放", "應依照使用道路面積成長比例及計程車空車率發放", "應依照縣、市人口及計程車駕駛人平均收入情形發放", "應依照縣、市人口及使用道路面積成長比例發放"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "e35adbcd1d79", "answer_pdf_sha1": "398158e7c48d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "511", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
